  'Great-great-grandfather': { en: `Great-great-grandfather`, ms: `Moyang tinggi`, tur: `Büyük büyük dede`, urd: `بڑے پردادا`, ben: `বৃদ্ধ প্রপিতামহ`, fas: `جدّ اعلیٰ`, zh: `高祖父`, yue: `高祖父`, ja: `高祖父`, ru: `Прапрадед`, es: `Tatarabuelo`, ko: `고조부`, ta: `மூதாதை`, si: `උත්තම මුත්තා` },
  Ancestor: { en: `Ancestor`, ms: `Leluhur`, tur: `Ata`, urd: `جدِ اعلیٰ`, ben: `পূর্বপুরুষ`, fas: `نیا`, zh: `先祖`, yue: `先祖`, ja: `先祖`, ru: `Предок`, es: `Antepasado`, ko: `조상`, ta: `மூதாதை`, si: `මුතුන් මිත්තා` },
  'Uncle (paternal)': { en: `Uncle (paternal)`, ms: `Bapa saudara (sebelah bapa)`, tur: `Amca`, urd: `چچا`, ben: `চাচা`, fas: `عمو`, zh: `叔父`, yue: `叔父`, ja: `叔父（父方）`, ru: `Дядя (по отцу)`, es: `Tío (paterno)`, ko: `삼촌(친가)`, ta: `சிற்றப்பா`, si: `පියාගේ සහෝදරයා` },
  'Brother (elder)': { en: `Brother (elder)`, ms: `Abang`, tur: `Ağabey`, urd: `بڑے بھائی`, ben: `বড় ভাই`, fas: `برادر بزرگ‌تر`, zh: `兄长`, yue: `兄長`, ja: `兄`, ru: `Старший брат`, es: `Hermano (mayor)`, ko: `형`, ta: `அண்ணன்`, si: `වැඩිමහල් සහෝදරයා` },
